 import { useState } from "react";

function PostDetails() {

  const [comment,setComment] = useState("");

  return (

    <div
      style={{
        width:"80%",
        margin:"40px auto"
      }}
    >

      <img
        src="https://images.unsplash.com/photo-1506744038136-46273834b3fb"
        alt=""
        style={{
          width:"100%",
          borderRadius:"20px"
        }}
      />

      <h1
        style={{
          marginTop:"20px"
        }}
      >
        MERN Stack Guide
      </h1>

      <p
        style={{
          marginTop:"20px",
          lineHeight:"1.8"
        }}
      >
        MERN stack is one of the most popular stacks
        used to build modern web applications.
      </p>

      <h2
        style={{
          marginTop:"40px"
        }}
      >
        Comments
      </h2>

      <div className="comment-box">
        Great article 👍
      </div>

      <div className="comment-box">
        Very helpful for beginners.
      </div>

      <textarea
        rows="4"
        placeholder="Add Comment"
        value={comment}
        onChange={(e)=>setComment(e.target.value)}
      />

      <button
        style={{
          marginTop:"15px"
        }}
      >
        Submit Comment
      </button>

    </div>

  );
}

export default PostDetails;
